class Solution:
    def makeArrayIncreasing(self, arr1, arr2):
        from functools import lru_cache
        b = sorted(set(arr2))
        n = len(arr1)
        INF = float('inf')
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(maxsize=None)
        def solve(i, prev):
            if i == n:
                return 0
            best = INF
            if arr1[i] > prev:
                best = min(best, solve(i + 1, arr1[i]))
            for v in b:
                if v > prev:
                    best = min(best, 1 + solve(i + 1, v))
                    break
            return best
        res = solve(0, -1)
        return res if res < INF else -1

