class Solution:
    def makeArrayIncreasing(self, arr1, arr2):
        import bisect
        arr2 = sorted(set(arr2))
        dp = {-1: 0}
        for num in arr1:
            ndp = {}
            for prev, ops in dp.items():
                if num > prev:
                    ndp[num] = min(ndp.get(num, float('inf')), ops)
                j = bisect.bisect_right(arr2, prev)
                if j < len(arr2):
                    cand = arr2[j]
                    ndp[cand] = min(ndp.get(cand, float('inf')), ops + 1)
            dp = ndp
            if not dp:
                return -1
        return min(dp.values())

