var makeArrayIncreasing = function(arr1, arr2) {
    const b = Array.from(new Set(arr2)).sort((a, c) => a - c);
    const upper = (x) => {
        let lo = 0, hi = b.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (b[mid] <= x) lo = mid + 1; else hi = mid;
        }
        return lo;
    };
    let dp = new Map([[-1, 0]]);
    for (const num of arr1) {
        const ndp = new Map();
        for (const [prev, ops] of dp) {
            if (num > prev) {
                const c = ndp.has(num) ? Math.min(ndp.get(num), ops) : ops;
                ndp.set(num, c);
            }
            const j = upper(prev);
            if (j < b.length) {
                const cand = b[j];
                const c = ndp.has(cand) ? Math.min(ndp.get(cand), ops + 1) : ops + 1;
                ndp.set(cand, c);
            }
        }
        dp = ndp;
        if (dp.size === 0) return -1;
    }
    let ans = Infinity;
    for (const v of dp.values()) ans = Math.min(ans, v);
    return ans;
};
